ranking.sparql:
PREFIX sd: <https://kumagallium.github.io/asterism/starrydata/ontology#>
PREFIX schema: <https://schema.org/>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX prov: <http://www.w3.org/ns/prov#>
SELECT ?curve ?ymax ?s ?comp ?p ?title WHERE {
  ?curve a sd:Curve ; sd:propertyY "ZT" ; sd:yMax ?ymax ; sd:ofSample ?s .
  ?s sd:fromPaper ?p .
  OPTIONAL { ?s sd:compositionString ?comp }
  OPTIONAL { ?p schema:name ?title }
  FILTER(?ymax <= 3.5)
} ORDER BY DESC(?ymax) LIMIT 10

composition.sparql_template:
PREFIX sd: <https://kumagallium.github.io/asterism/starrydata/ontology#>
PREFIX schema: <https://schema.org/>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX prov: <http://www.w3.org/ns/prov#>
SELECT DISTINCT ?sample ?comp ?name ?paper ?title WHERE {
  ?sample a sd:Sample .
  ?sample sd:compositionString ?comp .
  FILTER(CONTAINS(LCASE(STR(?comp)), "%Q%"))
  OPTIONAL { ?sample schema:name ?name }
  OPTIONAL { ?sample sd:fromPaper ?paper . OPTIONAL { ?paper schema:name ?title } }
} LIMIT 20

provenance.sparql_template:
PREFIX sd: <https://kumagallium.github.io/asterism/starrydata/ontology#>
PREFIX schema: <https://schema.org/>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX prov: <http://www.w3.org/ns/prov#>
SELECT ?etype ?fig ?py ?ymax ?ecomp ?ename ?sample ?scomp ?sname ?paper ?ptitle ?pid ?act ?atype ?atime WHERE {
  BIND(<%IRI%> AS ?e)
  OPTIONAL { ?e a ?etype . FILTER(STRSTARTS(STR(?etype), "https://kumagallium.github.io/asterism/starrydata/ontology#")) }
  OPTIONAL { ?e sd:figureName ?fig }
  OPTIONAL { ?e sd:propertyY ?py }
  OPTIONAL { ?e sd:yMax ?ymax }
  OPTIONAL { ?e sd:compositionString ?ecomp }
  OPTIONAL { ?e schema:name ?ename }
  OPTIONAL {
    ?e sd:ofSample ?sample .
    OPTIONAL { ?sample sd:compositionString ?scomp }
    OPTIONAL { ?sample schema:name ?sname }
    OPTIONAL { ?sample sd:fromPaper ?paper .
      OPTIONAL { ?paper schema:name ?ptitle }
      OPTIONAL { ?paper dcterms:identifier ?pid } }
  }
  OPTIONAL { ?e sd:fromPaper ?paper .
    OPTIONAL { ?paper schema:name ?ptitle }
    OPTIONAL { ?paper dcterms:identifier ?pid } }
  OPTIONAL {
    ?e prov:wasGeneratedBy ?act .
    OPTIONAL { ?act a ?atype . FILTER(STRSTARTS(STR(?atype), "https://kumagallium.github.io/asterism/starrydata/ontology#")) }
    OPTIONAL { ?act prov:atTime ?atime }
  }
}

cross.sparql:
PREFIX sd: <https://kumagallium.github.io/asterism/starrydata/ontology#>
PREFIX prov: <http://www.w3.org/ns/prov#>
# 2 ソースを 1 クエリで結合（ETL 不要・結合キー = 同じ sample IRI）
#   既定グラフ = starrydata（文献の測定値 ZT）
#   名前付きグラフ = Materials Project（計算された母相の結晶構造）
# 母相結晶構造ごとに 1 行（その相の最大 ZT・該当サンプル数）。
SELECT ?formula (MAX(?zt) AS ?ztmax) (COUNT(DISTINCT ?sample) AS ?nsamples)
       ?sg ?csys ?proto ?mp (SAMPLE(?sample) AS ?example)
       (SAMPLE(?comp) AS ?examplecomp) WHERE {
  ?curve a sd:Curve ; sd:propertyY "ZT" ; sd:yMax ?zt ; sd:ofSample ?sample .
  ?sample sd:compositionString ?comp .
  GRAPH <https://kumagallium.github.io/asterism/starrydata/graph/mp-links> {
    ?sample sd:hasHostStructure ?st .
    ?st sd:reducedHostFormula ?formula .
    OPTIONAL { ?st sd:spaceGroupSymbol ?sg }
    OPTIONAL { ?st sd:crystalSystem ?csys }
    OPTIONAL { ?st sd:structurePrototype ?proto }
    OPTIONAL { ?st sd:idealizedFrom ?mp }
  }
} GROUP BY ?formula ?sg ?csys ?proto ?mp
ORDER BY DESC(?ztmax) LIMIT 12
